const body = $input.first().json.body;
const events = body.events || [];
const results = [];
for (const event of events) {
  if (event.type === 'message' && event.message.type === 'text') {
    results.push({
      platform: 'line',
      userId: event.source.userId,
      replyToken: event.replyToken,
      text: event.message.text.trim(),
      senderId: event.source.userId
    });
  } else if (event.type === 'postback') {
    results.push({
      platform: 'line',
      userId: event.source.userId,
      replyToken: event.replyToken,
      text: event.postback.data.trim(),
      senderId: event.source.userId
    });
  }
}
return results.length > 0 ? results : [{ platform: 'line', userId: '', replyToken: '', text: '', senderId: '' }];

const body = $input.first().json.body;
const results = [];
const entries = body.entry || [];
for (const entry of entries) {
  const messagings = entry.messaging || [];
  for (const msg of messagings) {
    if (msg.message && msg.message.text) {
      results.push({
        platform: 'facebook',
        userId: msg.sender.id,
        replyToken: msg.sender.id,
        text: msg.message.text.trim(),
        senderId: msg.sender.id
      });
    } else if (msg.postback) {
      results.push({
        platform: 'facebook',
        userId: msg.sender.id,
        replyToken: msg.sender.id,
        text: msg.postback.payload.trim(),
        senderId: msg.sender.id
      });
    }
  }
}
return results.length > 0 ? results : [{ platform: 'facebook', userId: '', replyToken: '', text: '', senderId: '' }];

