if (!matched) {
  matched = {
    output: 'ขอบคุณที่ติดต่อมานะคะ 🐾\nแอดมินจะรีบตอบกลับโดยเร็วที่สุดค่ะ\n\nหรือสามารถดูข้อมูลเพิ่มเติมได้ที่\nhttps://www.pawtrythailand.com',
    quickReplies: ['คอร์สเรียน', 'บริการ', 'บทความ']
  };
}

if (platform === 'line') {
  const msg = {
    type: 'text',
    text: matched.output
  };
  if (matched.quickReplies && matched.quickReplies.length > 0) {
    msg.quickReply = {
      items: matched.quickReplies.map(label => ({
        type: 'action',
        action: { type: 'postback', label: label, data: label }
      }))
    };
  }
  return [{ json: { platform, userId, replyToken, messageType: 'text_flow', messages: [msg] } }];
} else {
  const result = { text: matched.output };
  if (matched.quickReplies && matched.quickReplies.length > 0) {
    result.quick_replies = matched.quickReplies.map(title => ({
      content_type: 'text', title, payload: title
    }));
  }
  return [{ json: { platform, userId, replyToken, messageType: 'text_flow', messages: [result] } }];
}
